import cn from 'clsx'
import PropTypes from 'prop-types'
import React from 'react'

export interface LayoutMainProps {
  /**
   * Date range of Copyright.
   */
  copyrightDate: string
  /**
   * Author's name.
   */
  authorName: string
  /**
   * Author's motto.
   */
  authorMotto: string
  /**
   * Main content.
   */
  content?: React.ReactNode
  /**
   * Footer content.
   */
  footer?: React.ReactNode
  /**
   * Display the backdrop
   */
  showBackdrop?: boolean
}

export const LayoutMain: React.FC<LayoutMainProps> = props => {
  const {
    content,
    footer,
    copyrightDate,
    authorMotto,
    authorName,
    showBackdrop = false,
  } = props

  return (
    <div className="kyokuya-post__layout-main">
      <div className="kyokuya-post__layout-main-content">
        {content}
        <footer className="kyokuya-post__layout-main-footer">
          <span>
            © {copyrightDate} {authorName}
          </span>
          <span>{authorMotto}</span>
        </footer>
        {footer}
      </div>
      <div className={cn('backdrop', { hidden: !showBackdrop })} />
    </div>
  )
}

LayoutMain.propTypes = {
  copyrightDate: PropTypes.string.isRequired,
  authorName: PropTypes.string.isRequired,
  authorMotto: PropTypes.string.isRequired,
  content: PropTypes.node,
  footer: PropTypes.node,
  showBackdrop: PropTypes.bool,
}

LayoutMain.displayName = 'KyokuyaLayoutPostLayoutMain'
export default LayoutMain
