const screenWidth = (): number =>
  typeof window !== 'undefined' ? window.screen.width : 2048

export const screen = {
  get xs(): boolean {
    const w = screenWidth()
    return w <= 767
  },
  get sm(): boolean {
    const w = screenWidth()
    return w >= 768 && w <= 991
  },
  get smPlus(): boolean {
    const w = screenWidth()
    return w >= 768
  },
  get smMinus(): boolean {
    const w = screenWidth()
    return w <= 991
  },
  get md(): boolean {
    const w = screenWidth()
    return w >= 992 && w <= 1199
  },
  get mdPlus(): boolean {
    const w = screenWidth()
    return w >= 992
  },
  get mdMinus(): boolean {
    const w = screenWidth()
    return w <= 1199
  },
  get lg(): boolean {
    const w = screenWidth()
    return w >= 1200
  },
}

export default screen
